// Build fetch URL
const body = $('Set Config').first().json.webhookBody || {};
const calendarName = body.calendar || $('Set Config').first().json.defaultCalendar;
const nextcloudUrl = $('Set Config').first().json.nextcloudUrl;
const nextcloudUser = $('Set Config').first().json.nextcloudUser;

let timeRange = '';
if (body.startDate || body.endDate) {
  const formatICalDate = (d) => {
    const year = d.getUTCFullYear();
    const month = String(d.getUTCMonth() + 1).padStart(2, '0');
    const day = String(d.getUTCDate()).padStart(2, '0');
    const hours = String(d.getUTCHours()).padStart(2, '0');
    const minutes = String(d.getUTCMinutes()).padStart(2, '0');
    const seconds = String(d.getUTCSeconds()).padStart(2, '0');
    return `${year}${month}${day}T${hours}${minutes}${seconds}Z`;
  };
  const start = body.startDate ? new Date(body.startDate) : new Date();
  const end = body.endDate ? new Date(body.endDate) : new Date(start.getTime() + 30 * 24 * 60 * 60 * 1000);
  timeRange = `?start=${formatICalDate(start)}&end=${formatICalDate(end)}`;
}

return [{ json: { url: `${nextcloudUrl}/remote.php/dav/calendars/${nextcloudUser}/${calendarName}${timeRange}`, calendarName } }];

// Parse CalDAV XML response for VEVENT
const xml = $input.first().json.data || '';
const calendarName = $('Build Fetch URL').first().json.calendarName;
const events = [];
const veventMatches = xml.match(/<cal:VEVENT[^>]*>[\s\S]*?<\/cal:VEVENT>/gi) || [];

for (const vevent of veventMatches) {
  const extract = (tag) => {
    const match = vevent.match(new RegExp(`<cal:${tag}[^>]*>([^<]*)<\\/${tag}>`, 'i'));
    return match ? match[1] : null;
  };

  const parseICalDate = (icalDate) => {
    if (!icalDate) return null;
    if (icalDate.length === 8) {
      return `${icalDate.substring(0,4)}-${icalDate.substring(4,6)}-${icalDate.substring(6,8)}`;
    }
    return `${icalDate.substring(0,4)}-${icalDate.substring(4,6)}-${icalDate.substring(6,8)}T${icalDate.substring(9,11)}:${icalDate.substring(11,13)}:${icalDate.substring(13,15)}Z`;
  };

  const dtstart = extract('DTSTART');
  const isAllDay = dtstart && !dtstart.includes('T');

  // Extract attendees
  const attendees = [];
  const attendeeMatches = vevent.match(/<cal:ATTENDEE[^>]*>[^<]*<\/cal:ATTENDEE>/gi) || [];
  for (const att of attendeeMatches) {
    const email = att.match(/mailto:([^<]*)/i);
    const cn = att.match(/CN=([^;]*)/i);
    const partstat = att.match(/PARTSTAT=([^;]*)/i);
    if (email) attendees.push({ email: email[1], name: cn ? cn[1] : null, status: partstat ? partstat[1] : 'NEEDS-ACTION' });
  }

  events.push({
    uid: extract('UID'),
    title: extract('SUMMARY') || 'Untitled',
    description: extract('DESCRIPTION'),
    start: parseICalDate(dtstart),
    end: parseICalDate(extract('DTEND')),
    allDay: isAllDay,
    location: extract('LOCATION'),
    status: extract('STATUS') || 'CONFIRMED',
    priority: extract('PRIORITY') ? parseInt(extract('PRIORITY')) : null,
    transparency: extract('TRANSP'),
    categories: extract('CATEGORIES') ? extract('CATEGORIES').split(',').map(c => c.trim()) : [],
    recurrence: extract('RRULE'),
    attendees,
    organizer: null,
    url: extract('URL'),
    sequence: extract('SEQUENCE') ? parseInt(extract('SEQUENCE')) : 0,
    calendar: calendarName
  });
}

return [{ json: { success: true, events, count: events.length } }];

// Build ICS for create event
const body = $('Set Config').first().json.webhookBody;
const eventId = Date.now();
const calendarName = body.calendar || $('Set Config').first().json.defaultCalendar;

const formatICalDate = (d) => {
  const pad = (n) => String(n).padStart(2, '0');
  return `${d.getUTCFullYear()}${pad(d.getUTCMonth()+1)}${pad(d.getUTCDate())}T${pad(d.getUTCHours())}${pad(d.getUTCMinutes())}${pad(d.getUTCSeconds())}Z`;
};
const formatICalDateOnly = (d) => `${d.getUTCFullYear()}${String(d.getUTCMonth()+1).padStart(2,'0')}${String(d.getUTCDate()).padStart(2,'0')}`;
const parseDate = (s) => { if (!s) return null; const d = new Date(s); return isNaN(d.getTime()) ? null : d; };

const now = new Date();
const startDate = parseDate(body.start);
const endDate = parseDate(body.end);
const isAllDay = body.allDay === true;

const lines = ['BEGIN:VCALENDAR','VERSION:2.0','PRODID:-//n8n//Nextcloud//EN','CALSCALE:GREGORIAN','BEGIN:VEVENT',`UID:n8n-event-${eventId}`,`DTSTAMP:${formatICalDate(now)}`];

if (body.title) lines.push(`SUMMARY:${body.title}`);
if (startDate) lines.push(isAllDay ? `DTSTART;VALUE=DATE:${formatICalDateOnly(startDate)}` : `DTSTART:${formatICalDate(startDate)}`);
if (endDate) lines.push(isAllDay ? `DTEND;VALUE=DATE:${formatICalDateOnly(endDate)}` : `DTEND:${formatICalDate(endDate)}`);
else if (startDate && !isAllDay) lines.push(`DTEND:${formatICalDate(new Date(startDate.getTime() + 3600000))}`);
if (body.description) lines.push(`DESCRIPTION:${body.description}`);
if (body.location) lines.push(`LOCATION:${body.location}`);

if (body.status) { const m = {'tentative':'TENTATIVE','confirmed':'CONFIRMED','cancelled':'CANCELLED'}; lines.push(`STATUS:${m[body.status]||body.status}`); } else lines.push('STATUS:CONFIRMED');
if (body.transparency) { const m = {'busy':'OPAQUE','free':'TRANSPARENT'}; lines.push(`TRANSP:${m[body.transparency]||body.transparency}`); } else lines.push('TRANSP:OPAQUE');
if (body.priority !== undefined) lines.push(`PRIORITY:${Math.min(9,Math.max(1,parseInt(body.priority)))}`);
if (body.categories) lines.push(`CATEGORIES:${Array.isArray(body.categories)?body.categories.join(','):body.categories}`);
if (body.url) lines.push(`URL:${body.url}`);
if (body.recurrence) lines.push(`RRULE:${body.recurrence}`);

if (body.attendees) {
  (Array.isArray(body.attendees) ? body.attendees : [body.attendees]).forEach(a => {
    if (a.email) lines.push(`ATTENDEE;${a.name?`CN=${a.name};`:''}CUTYPE=INDIVIDUAL;ROLE=REQ-PARTICIPANT;PARTSTAT=${a.status||'NEEDS-ACTION'}:mailto:${a.email}`);
  });
}

lines.push('BEGIN:VALARM','ACTION:DISPLAY','DESCRIPTION:Reminder','TRIGGER:-PT15M','END:VALARM','SEQUENCE:0','END:VEVENT','END:VCALENDAR');

const nextcloudUrl = $('Set Config').first().json.nextcloudUrl;
const nextcloudUser = $('Set Config').first().json.nextcloudUser;
return [{ json: { icsBody: lines.join('\r\n'), eventUrl: `${nextcloudUrl}/remote.php/dav/calendars/${nextcloudUser}/${calendarName}/${eventId}.ics`, calendarName } }];

// Build ICS for update event
const body = $('Set Config').first().json.webhookBody;
if (!body.eventUid) return [{ json: { success: false, message: 'eventUid is required' } }];

const calendarName = body.calendar || $('Set Config').first().json.defaultCalendar;
const formatICalDate = (d) => { const pad = (n) => String(n).padStart(2,'0'); return `${d.getUTCFullYear()}${pad(d.getUTCMonth()+1)}${pad(d.getUTCDate())}T${pad(d.getUTCHours())}${pad(d.getUTCMinutes())}${pad(d.getUTCSeconds())}Z`; };
const formatICalDateOnly = (d) => `${d.getUTCFullYear()}${String(d.getUTCMonth()+1).padStart(2,'0')}${String(d.getUTCDate()).padStart(2,'0')}`;
const parseDate = (s) => { if (!s) return null; const d = new Date(s); return isNaN(d.getTime()) ? null : d; };

const now = new Date();
const startDate = parseDate(body.start);
const endDate = parseDate(body.end);
const isAllDay = body.allDay === true;
const sequence = (body.sequence || 0) + 1;

const lines = ['BEGIN:VCALENDAR','VERSION:2.0','PRODID:-//n8n//Nextcloud//EN','CALSCALE:GREGORIAN','BEGIN:VEVENT',`UID:${body.eventUid}`,`DTSTAMP:${formatICalDate(now)}`];

if (body.title !== undefined) lines.push(`SUMMARY:${body.title}`);
if (startDate) lines.push(isAllDay ? `DTSTART;VALUE=DATE:${formatICalDateOnly(startDate)}` : `DTSTART:${formatICalDate(startDate)}`);
if (endDate) lines.push(isAllDay ? `DTEND;VALUE=DATE:${formatICalDateOnly(endDate)}` : `DTEND:${formatICalDate(endDate)}`);
if (body.description !== undefined) lines.push(`DESCRIPTION:${body.description}`);
if (body.location !== undefined) lines.push(`LOCATION:${body.location}`);
if (body.status) { const m = {'tentative':'TENTATIVE','confirmed':'CONFIRMED','cancelled':'CANCELLED'}; lines.push(`STATUS:${m[body.status]||body.status}`); }
if (body.transparency) { const m = {'busy':'OPAQUE','free':'TRANSPARENT'}; lines.push(`TRANSP:${m[body.transparency]||body.transparency}`); }
if (body.priority !== undefined) lines.push(`PRIORITY:${Math.min(9,Math.max(1,parseInt(body.priority)))}`);
if (body.categories) lines.push(`CATEGORIES:${Array.isArray(body.categories)?body.categories.join(','):body.categories}`);
if (body.recurrence !== undefined && body.recurrence) lines.push(`RRULE:${body.recurrence}`);
lines.push(`SEQUENCE:${sequence}`);

lines.push('END:VEVENT','END:VCALENDAR');

const nextcloudUrl = $('Set Config').first().json.nextcloudUrl;
const nextcloudUser = $('Set Config').first().json.nextcloudUser;
return [{ json: { icsBody: lines.join('\r\n'), eventUrl: `${nextcloudUrl}/remote.php/dav/calendars/${nextcloudUser}/${calendarName}/${body.eventUid}.ics`, sequence } }];

const body = $('Set Config').first().json.webhookBody;
if (!body.eventUid) return [{ json: { success: false, message: 'eventUid is required' } }];
const calendarName = body.calendar || $('Set Config').first().json.defaultCalendar;
const nextcloudUrl = $('Set Config').first().json.nextcloudUrl;
const nextcloudUser = $('Set Config').first().json.nextcloudUser;
return [{ json: { eventUrl: `${nextcloudUrl}/remote.php/dav/calendars/${nextcloudUser}/${calendarName}/${body.eventUid}.ics`, eventUid: body.eventUid, calendarName } }];
